public int minOperations(int[][] grid, int x) {
    int minElement = Integer.MAX_VALUE;
    for (int[] row : grid) {
        for (int cell : row) {
            minElement = Math.min(minElement, cell);
        }
    }

    int minOperations = Integer.MAX_VALUE;
    for (int base = minElement; ; --base) {
        int operations = 0;
        boolean impossible = false;
        for (int[] row : grid) {
            if (impossible) break;
            for (int cell : row) {
                int diff = Math.abs(cell - base);
                if (diff % x != 0) {
                    impossible = true;
                    break;
                }
                operations += diff / x;
            }
        }
        if (impossible) break;
        minOperations = Math.min(minOperations, operations);
    }

    return minOperations == Integer.MAX_VALUE ? -1 : minOperations;
}
```

